INSERT INTO public.questions (id, exam_id, paper_id, subject_id, chapter_id, question_type, question_text, options, correct_answer, correct_answer_json, auto_gradable, source, is_active, version, source_meta, explanation)
VALUES
  ('cpa-moex-00891', 'cpa', 'cpa-moex-106-78566e18', 'sub-cpa-01', NULL, 'single_choice', '甲公司於20X5年1月1日銷售手機10,000支並附18個月之產品保固。20X6年12月31日，客戶 反映手機會過熱導致當機，甲公司發現約有1%產品出現問題，該產品瑕疵屬合理範圍，因已過保固 期限，故甲公司僅願以維修成本之優惠價格每支$2,500幫客戶維修，原維修價格每支$4,000。客戶對 甲公司提供之方案並不滿意。甲公司於20X6年12月31日之財務報表，應如何表達此一事件？', '["不符負債之定義，不認列負債", "符合負債之定義，但未來經濟效益流出可能性不高，不認列負債", "符合負債之定義，未來經濟效益很可能流出，但金額無法可靠衡量，不認列負債", "符合負債之定義，未來經濟效益很可能流出，且金額能可靠衡量，認列負債"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:11+00:00", "source_pdf_sha1": "ea4ee0145b00", "answer_pdf_sha1": "34786ebea20d", "source_family": "moex-gov-tw", "moex": {"exam_code": "106140", "c": "803", "s": "0206", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "中級會計學", "year": "106", "exam_name": "106年專門職業及技術人員高等考試會計師、不動產估價師、專利師考試", "original_question_number": 1, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-00892', 'cpa', 'cpa-moex-106-78566e18', 'sub-cpa-01', NULL, 'single_choice', '甲公司於20X1年8月1日決定處分其餐廳部門，並於12月20日以$600,000之價款出售該部門，當 時該部門之淨資產帳面價值為$540,000。另外，餐廳部門在20X1年1月1日至8月1日間之稅前營 業損失為$50,000，8月1日至12月20日間之稅前營業損失為$15,000。假設所得稅率為20%，而該 項處分符合停業單位之定義。試問，甲公司在20X1年度綜合損益表中停業單位損益為多少？', '["損失$4,000", "利益$36,000", "利益$48,000", "損失$52,000"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:11+00:00", "source_pdf_sha1": "ea4ee0145b00", "answer_pdf_sha1": "34786ebea20d", "source_family": "moex-gov-tw", "moex": {"exam_code": "106140", "c": "803", "s": "0206", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "中級會計學", "year": "106", "exam_name": "106年專門職業及技術人員高等考試會計師、不動產估價師、專利師考試", "original_question_number": 2, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-00893', 'cpa', 'cpa-moex-106-78566e18', 'sub-cpa-01', NULL, 'single_choice', '甲投信公司於 20Xl 年 7 月 1 日承接某客戶之股票投資服務，合約期間 1 年，合約包含固定報酬 $10,000,000另加計績效獎金。績效獎金係於合約結束日根據委託帳戶於合約期間之投資績效計算， 若實際投資績效能超越10%，另發績效獎金$2,000,000。截至20Xl年12月31日，此委託帳戶之投 資績效已達12%，故甲投信公司評估在20X2年6月30日合約結束時，實際績效很有可能超越10%。 請問甲投信公司對此投資委託服務合約於20Xl年度應認列相關收入若干？', '["$0", "$5,000,000", "$6,000,000", "$7,000,000"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:11+00:00", "source_pdf_sha1": "ea4ee0145b00", "answer_pdf_sha1": "34786ebea20d", "source_family": "moex-gov-tw", "moex": {"exam_code": "106140", "c": "803", "s": "0206", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "中級會計學", "year": "106", "exam_name": "106年專門職業及技術人員高等考試會計師、不動產估價師、專利師考試", "original_question_number": 3, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-00894', 'cpa', 'cpa-moex-106-78566e18', 'sub-cpa-01', NULL, 'single_choice', '甲公司7月31日銀行對帳單與公司帳上的銀行存款餘額分別為$83,300與$55,500，二者差異包括在 途存款$29,200、未兌現支票$50,000及甲公司支出記帳錯誤$7,000。8月份帳載銀行存款存入及支出 記錄分別為$528,750及$485,000，公司8月份銀行存款帳載記錄包括7月31日調節表應作的調整分', '["7月31日未兌現支票中，有$10,000於 8月底仍未兌現", "8月銀行代為收訖之票據$6,500，甲公司尚未入帳", "甲公司8月25日開立支票 $18,400，銀行已兌付，但帳上誤記為$14,800。試問甲公司8月31日正確銀行存款金額為何？", "$95,150"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:11+00:00", "source_pdf_sha1": "ea4ee0145b00", "answer_pdf_sha1": "34786ebea20d", "source_family": "moex-gov-tw", "moex": {"exam_code": "106140", "c": "803", "s": "0206", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "中級會計學", "year": "106", "exam_name": "106年專門職業及技術人員高等考試會計師、不動產估價師、專利師考試", "original_question_number": 4, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-00895', 'cpa', 'cpa-moex-106-78566e18', 'sub-cpa-01', NULL, 'single_choice', '甲公司將帳面金額$600,000，利率4%之10年期放款組合之所有本金與利息以無追索權方式出售予乙 公司而取得等同公允價值之現金$620,000。甲公司仍繼續負責向原放款客戶收款後轉交予乙公司，未 來預期將收取之服務費之現值為$20,000，但提供該服務之足額補償之現值為$50,000。甲公司關於出 售該放款組合應認列之處分（損）益為（不考慮所得稅影響）：', '["$(10,000)", "$0", "$20,000", "$28,151"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:11+00:00", "source_pdf_sha1": "ea4ee0145b00", "answer_pdf_sha1": "34786ebea20d", "source_family": "moex-gov-tw", "moex": {"exam_code": "106140", "c": "803", "s": "0206", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "中級會計學", "year": "106", "exam_name": "106年專門職業及技術人員高等考試會計師、不動產估價師、專利師考試", "original_question_number": 5, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-00896', 'cpa', 'cpa-moex-106-78566e18', 'sub-cpa-01', NULL, 'single_choice', '甲果園於20X5年10月底採收1,000公斤蘋果，計發生$50,000採收支出，並立即將600公斤蘋果運 至拍賣市場交易。20X5年底尚有400公斤蘋果未售出，每公斤計已發生$3冷藏支出。採收時蘋果每 公斤市場報價為$100，20X5年底市場報價為$105。若運至拍賣市場交易之每公斤運費為$10，售出1 公斤蘋果需繳交$2交易規費，則20X5年底應列報蘋果存貨之金額為何？', '["$34,000", "$35,200", "$36,400", "$37,200"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:11+00:00", "source_pdf_sha1": "ea4ee0145b00", "answer_pdf_sha1": "34786ebea20d", "source_family": "moex-gov-tw", "moex": {"exam_code": "106140", "c": "803", "s": "0206", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "中級會計學", "year": "106", "exam_name": "106年專門職業及技術人員高等考試會計師、不動產估價師、專利師考試", "original_question_number": 6, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-00897', 'cpa', 'cpa-moex-106-78566e18', 'sub-cpa-01', NULL, 'single_choice', '甲公司於20X1年初以$800,000取得一項專利權，剩餘專利期間10年，預期經濟效益8年。甲公司 於20X5年7月1日以該專利權，外加現金$400,000，與乙公司交換功能類似之專利權，乙公司之專 利權於交換時，尚有專利期間5年，預期經濟效益3.5年。若此項資產交換具有商業實質，且甲公司 原有專利權於交換時之公允價值為$300,000，則甲公司20X5年與新專利權、舊專利權及資產交換有 關而減少淨利的總金額為何？', '["$100,000", "$150,000", "$200,000", "$250,000"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:11+00:00", "source_pdf_sha1": "ea4ee0145b00", "answer_pdf_sha1": "34786ebea20d", "source_family": "moex-gov-tw", "moex": {"exam_code": "106140", "c": "803", "s": "0206", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "中級會計學", "year": "106", "exam_name": "106年專門職業及技術人員高等考試會計師、不動產估價師、專利師考試", "original_question_number": 7, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-00898', 'cpa', 'cpa-moex-106-78566e18', 'sub-cpa-01', NULL, 'single_choice', '甲公司於20X1年初以$3,000,000購置大樓一棟，預估耐用年限10年，直線法折舊，無殘值。該大 樓於20X3年底以前出租予甲公司員工作為宿舍，並曾於20X2年底發生重估增值$800,000，且重估 增值將於使用該資產時逐步轉出，重估價未改變殘值、耐用年限及折舊方法之預估。若甲公司於20X3 年底將該大樓轉為營業租賃使用，而分類該大樓為投資性不動產，且該大樓於20X3年底的公允價值 為$1,900,000，則該大樓減少甲公司20X3年損益的總金額為何？', '["$200,000", "$600,000", "$1,100,000", "$1,300,000"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:11+00:00", "source_pdf_sha1": "ea4ee0145b00", "answer_pdf_sha1": "34786ebea20d", "source_family": "moex-gov-tw", "moex": {"exam_code": "106140", "c": "803", "s": "0206", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "中級會計學", "year": "106", "exam_name": "106年專門職業及技術人員高等考試會計師、不動產估價師、專利師考試", "original_question_number": 8, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-00899', 'cpa', 'cpa-moex-106-78566e18', 'sub-cpa-01', NULL, 'single_choice', '丁公司於20Xl年初成立，其20Xl年與20X2年有關存貨的進銷資料如下： 年度  進貨數量  每單位進貨成本  銷售量  單位售價 20X1  3,000  $200  2,500  $250 20X2  2,500  $176  2,000  $222 試計算於加權平均法與先進先出法之下，丁公司20X2年之存貨週轉率分別為何（四捨五入至小數點 後第二位）？', '["加權平均法：2.00；先進先出法：2.07", "加權平均法：1.87；先進先出法：2.07", "加權平均法：2.57；先進先出法：2.64", "加權平均法：2.00；先進先出法：2.64"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:11+00:00", "source_pdf_sha1": "ea4ee0145b00", "answer_pdf_sha1": "34786ebea20d", "source_family": "moex-gov-tw", "moex": {"exam_code": "106140", "c": "803", "s": "0206", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "中級會計學", "year": "106", "exam_name": "106年專門職業及技術人員高等考試會計師、不動產估價師、專利師考試", "original_question_number": 9, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-00900', 'cpa', 'cpa-moex-106-78566e18', 'sub-cpa-01', NULL, 'single_choice', '乙公司於20X1年1月1日發行利率8%，面額$2,000,000，20X7年1月1日到期之債券。市場有效 利率為12%，因而此債券採折價發行，折價金額為$300,000，公司採攤銷後成本法報導此項債務。乙 公司誤採直線法而非正確之有效利息法攤銷債券折價，試問此項錯誤對乙公司債券帳面金額的影響 為何？ 20X1年12月31日   20X7年1月1日', '["高估               低估", "高估               無影響", "低估               高估", "低估               無影響"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:11+00:00", "source_pdf_sha1": "ea4ee0145b00", "answer_pdf_sha1": "34786ebea20d", "source_family": "moex-gov-tw", "moex": {"exam_code": "106140", "c": "803", "s": "0206", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "中級會計學", "year": "106", "exam_name": "106年專門職業及技術人員高等考試會計師、不動產估價師、專利師考試", "original_question_number": 10, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL)
